void setMotorPower(float left_pwm, float right_pwm) {
  // 限制允许的功率范围，最大绝对值为75
  if (abs(left_pwm) <= 75 && abs(right_pwm) <= 75) {
    // 设置初始方向
    bool L_DIR = (left_pwm < 0) ? REV : FWD;
    bool R_DIR = (right_pwm < 0) ? REV : FWD;

    // 设置电机功率
    analogWrite(L_PWM_PIN, int(abs(left_pwm)));
    analogWrite(R_PWM_PIN, int(abs(right_pwm)));

    // 设置电机方向
    digitalWrite(L_DIR_PIN, L_DIR);
    digitalWrite(R_DIR_PIN, R_DIR);
  }
}
```

